const drafts_expired = $('Expire Drafts').all().length;
const approvals_expired = $('Expire Approvals').all().length;

const blocks = [
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `:hourglass: *Daily expiry:* ${drafts_expired} draft(s) expired, ${approvals_expired} approval(s) expired`
    }
  }
];

return [{
  json: {
    drafts_expired,
    approvals_expired,
    slack_blocks: blocks,
    slack_text_fallback: `Daily expiry: ${drafts_expired} drafts, ${approvals_expired} approvals`
  }
}];
